/**
 * Configuration module for Voynich character position heatmap visualizer.
 * 
 * Transcription config (char ordering, display mappings, etc.) is loaded from
 * docs/output/transcription_config.json - the single source of truth generated by
 * the Python processing scripts.
 */

const Config = (function() {
  
  let CHAR_DISPLAY = {};
  let CHAR_ORDER = [];
  let AGGREGATION_DEFINITIONS = {};
  let _configLoaded = false;
  
  /**
   * Load transcription config from JSON.
   * @param {Object} config - Config object from transcription_config.json
   */
  function loadTranscriptionConfig(config) {
    CHAR_DISPLAY = config.char_display || {};
    CHAR_ORDER = config.char_order || [];
    AGGREGATION_DEFINITIONS = config.aggregations || {};
    _configLoaded = true;
  }
  
  function isConfigLoaded() {
    return _configLoaded;
  }
  
  // Heatmap color scales
  const COLORMAPS = {
    blue: {
      name: 'Blue',
      stops: [
        { pos: 0, r: 248, g: 249, b: 250 },
        { pos: 1, r: 74, g: 144, b: 217 },
      ]
    },
    viridis: {
      name: 'Viridis',
      stops: [
        { pos: 0, r: 68, g: 1, b: 84 },
        { pos: 0.25, r: 59, g: 82, b: 139 },
        { pos: 0.5, r: 33, g: 145, b: 140 },
        { pos: 0.75, r: 94, g: 201, b: 98 },
        { pos: 1, r: 253, g: 231, b: 37 },
      ]
    },
    magma: {
      name: 'Magma',
      stops: [
        { pos: 0, r: 0, g: 0, b: 4 },
        { pos: 0.25, r: 81, g: 18, b: 124 },
        { pos: 0.5, r: 183, g: 55, b: 121 },
        { pos: 0.75, r: 254, g: 159, b: 109 },
        { pos: 1, r: 252, g: 253, b: 191 },
      ]
    },
    plasma: {
      name: 'Plasma',
      stops: [
        { pos: 0, r: 13, g: 8, b: 135 },
        { pos: 0.25, r: 126, g: 3, b: 168 },
        { pos: 0.5, r: 204, g: 71, b: 120 },
        { pos: 0.75, r: 248, g: 149, b: 64 },
        { pos: 1, r: 240, g: 249, b: 33 },
      ]
    },
    hot: {
      name: 'Hot',
      stops: [
        { pos: 0, r: 255, g: 255, b: 255 },
        { pos: 0.33, r: 255, g: 255, b: 0 },
        { pos: 0.66, r: 255, g: 100, b: 0 },
        { pos: 1, r: 128, g: 0, b: 0 },
      ]
    },
    greyscale: {
      name: 'Greyscale',
      stops: [
        { pos: 0, r: 255, g: 255, b: 255 },
        { pos: 1, r: 0, g: 0, b: 0 },
      ]
    },
  };
  
  let currentColormap = 'blue';
  
  // Default settings
  const DEFAULTS = {
    aggregation: 'all',
    sortBy: 'position',
    positionMode: 'word',
    scaling: 'sqrt',
    colormap: 'blue',
    useVoynichFont: true,
    maxWordLength: 9,
    maxLineLength: 12,
    cellPadding: 2,
    rowHeight: 80,
  };
  
  /**
   * Apply scaling to a ratio value (0-1).
   * Returns scaled value (0-1) for heatmap coloring.
   */
  function applyScaling(value, scaling) {
    if (value <= 0) return 0;
    
    switch (scaling) {
      case 'sqrt':
        // sqrt scaling: amplifies smaller values
        return Math.sqrt(value);
      case 'log':
        // log10 scaling: map from [0,1] using log
        // Use a small epsilon to handle very small values
        // Scale so that log10(1) = 0 maps to 1, and smaller values scale down
        const minLog = -4;  // log10(0.0001) = -4
        const logVal = Math.log10(Math.max(value, 0.0001));
        return Math.max(0, (logVal - minLog) / (0 - minLog));
      case 'linear':
      default:
        return value;
    }
  }
  
  /**
   * Interpolate between colormap stops.
   */
  function interpolateColor(stops, value) {
    const clampedValue = Math.max(0, Math.min(1, value));
    
    // Find the two stops to interpolate between
    let lower = stops[0];
    let upper = stops[stops.length - 1];
    
    for (let i = 0; i < stops.length - 1; i++) {
      if (clampedValue >= stops[i].pos && clampedValue <= stops[i + 1].pos) {
        lower = stops[i];
        upper = stops[i + 1];
        break;
      }
    }
    
    // Calculate interpolation factor
    const range = upper.pos - lower.pos;
    const t = range > 0 ? (clampedValue - lower.pos) / range : 0;
    
    const r = Math.round(lower.r + (upper.r - lower.r) * t);
    const g = Math.round(lower.g + (upper.g - lower.g) * t);
    const b = Math.round(lower.b + (upper.b - lower.b) * t);
    
    return { r, g, b };
  }
  
  /**
   * Get color for a heatmap value (0-1).
   */
  function getHeatmapColor(value, alpha = 1, colormapName = null) {
    const mapName = colormapName || currentColormap;
    const colormap = COLORMAPS[mapName] || COLORMAPS.blue;
    const { r, g, b } = interpolateColor(colormap.stops, value);
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  }
  
  /**
   * Set the current colormap.
   */
  function setColormap(name) {
    if (COLORMAPS[name]) {
      currentColormap = name;
    }
  }
  
  /**
   * Get available colormap names.
   */
  function getColormapNames() {
    return Object.entries(COLORMAPS).map(([key, val]) => ({ id: key, name: val.name }));
  }
  
  /**
   * Get display label for a character.
   */
  function getCharDisplay(char, useVoynichFont = false) {
    if (useVoynichFont) {
      const fontMap = {
        '1': 'i', '2': 'ii', '3': 'iii', '4': 'iiii',
        '6': 'e', '7': 'ee', '8': 'eee', '9': 'eeee',
        'C': 'ch', 'S': 'sh', 'T': 'cth', 'P': 'cph', 'F': 'cfh', 'K': 'ckh',
      };
      return fontMap[char] || char;
    }
    return CHAR_DISPLAY[char] || char;
  }
  
  /**
   * Sort characters according to preferred order.
   */
  function sortCharacters(chars) {
    const orderMap = new Map(CHAR_ORDER.map((c, i) => [c, i]));
    return [...chars].sort((a, b) => {
      const aIdx = orderMap.has(a) ? orderMap.get(a) : 999;
      const bIdx = orderMap.has(b) ? orderMap.get(b) : 999;
      return aIdx - bIdx;
    });
  }
  
  /**
   * Sort characters by a specific criterion for position data.
   */
  function sortCharactersBy(charData, sortBy, positionMode = 'word') {
    const entries = Object.entries(charData);
    const dataKey = positionMode === 'word' ? 'word_position' : 'line_position';
    // Use appropriate length range based on mode
    const lengthRange = positionMode === 'word' ? [3, 4, 5, 6, 7, 8, 9] : [4, 5, 6, 7, 8, 9, 10, 11, 12];
    
    switch (sortBy) {
      case 'total':
        entries.sort((a, b) => (b[1].total || 0) - (a[1].total || 0));
        break;
      case 'position':
        // Order from most start-preferring (top) to most end-preferring (bottom)
        // Uses (start - end) ratio difference averaged across word/line lengths
        entries.sort((a, b) => {
          const aRatios = a[1][dataKey]?.ratios || {};
          const bRatios = b[1][dataKey]?.ratios || {};
          const aScore = lengthRange.reduce((sum, len) => {
            const ratios = aRatios[len];
            if (!ratios || ratios.length === 0) return sum;
            return sum + (ratios[0] || 0) - (ratios[ratios.length - 1] || 0);
          }, 0) / lengthRange.length;
          const bScore = lengthRange.reduce((sum, len) => {
            const ratios = bRatios[len];
            if (!ratios || ratios.length === 0) return sum;
            return sum + (ratios[0] || 0) - (ratios[ratios.length - 1] || 0);
          }, 0) / lengthRange.length;
          return bScore - aScore;
        });
        break;
      case 'start':
        // Sort by preference for first position in longer words/lines
        entries.sort((a, b) => {
          const aRatios = a[1][dataKey]?.ratios || {};
          const bRatios = b[1][dataKey]?.ratios || {};
          const aScore = lengthRange.reduce((sum, len) => {
            const ratios = aRatios[len];
            return sum + (ratios && ratios[0] ? ratios[0] : 0);
          }, 0) / lengthRange.length;
          const bScore = lengthRange.reduce((sum, len) => {
            const ratios = bRatios[len];
            return sum + (ratios && ratios[0] ? ratios[0] : 0);
          }, 0) / lengthRange.length;
          return bScore - aScore;
        });
        break;
      case 'end':
        // Sort by preference for last position in longer words/lines
        entries.sort((a, b) => {
          const aRatios = a[1][dataKey]?.ratios || {};
          const bRatios = b[1][dataKey]?.ratios || {};
          const aScore = lengthRange.reduce((sum, len) => {
            const ratios = aRatios[len];
            return sum + (ratios && ratios.length > 0 ? ratios[ratios.length - 1] : 0);
          }, 0) / lengthRange.length;
          const bScore = lengthRange.reduce((sum, len) => {
            const ratios = bRatios[len];
            return sum + (ratios && ratios.length > 0 ? ratios[ratios.length - 1] : 0);
          }, 0) / lengthRange.length;
          return bScore - aScore;
        });
        break;
      case 'alpha':
        return sortCharacters(entries.map(e => e[0]));
      default:
        entries.sort((a, b) => (b[1].total || 0) - (a[1].total || 0));
    }
    
    return entries.map(e => e[0]);
  }
  
  /**
   * Get aggregation description.
   */
  function getAggregationDescription(name) {
    if (AGGREGATION_DEFINITIONS[name]) {
      return AGGREGATION_DEFINITIONS[name].description;
    }
    return name;
  }
  
  return {
    get CHAR_DISPLAY() { return CHAR_DISPLAY; },
    get CHAR_ORDER() { return CHAR_ORDER; },
    get AGGREGATION_DEFINITIONS() { return AGGREGATION_DEFINITIONS; },
    COLORMAPS,
    DEFAULTS,
    loadTranscriptionConfig,
    isConfigLoaded,
    getHeatmapColor,
    setColormap,
    getColormapNames,
    getCharDisplay,
    sortCharacters,
    sortCharactersBy,
    getAggregationDescription,
    applyScaling,
  };
})();
